-- 502_fix_document_templates_seed.sql
-- Inserts the 12 contract templates, 6 signed envelopes, and 12 signatures
-- that migration 494 couldn't insert due to multi-line body_md strings.
-- Safe to re-run (INSERT OR IGNORE throughout).
-- ══════════════════════════════════════════════════════════════════════════════

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_isda_2002_v1', 'isda.2002.master.v1', 'ISDA 2002 Master Agreement', 'other', 'ISDA 2002 Master Agreement — Party A: {{party_a_name}} (LEI: {{party_a_lei}}) | Party B: {{party_b_name}} (LEI: {{party_b_lei}}) | Governing Law: Republic of South Africa (SARB D3/2023 Uncleared Margin Rules) | Base Currency: ZAR. FSCA FMA Act No. 19 of 2012 applies.', '[{"key":"party_a_name","desc":"Legal name of Party A"},{"key":"party_a_lei","desc":"LEI of Party A"},{"key":"party_b_name","desc":"Legal name of Party B"},{"key":"party_b_lei","desc":"LEI of Party B"}]', '[{"role":"trader","label":"Party A Authorised Signatory"},{"role":"trader","label":"Party B Authorised Signatory"}]', 'ZA-FSCA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_service_agreement_v1', 'service.agreement.standard.v1', 'Platform Service Agreement', 'other', 'Platform Service Agreement — Service Provider: {{provider_name}} | Client: {{client_name}} | Services: {{services_description}} | Commencement: {{start_date}} | Fee: ZAR {{monthly_fee}} per month | Governed by Consumer Protection Act 68 of 2008.', '[{"key":"provider_name","desc":"Service provider legal name"},{"key":"client_name","desc":"Client legal name"},{"key":"services_description","desc":"Description of services"},{"key":"start_date","desc":"Commencement date"},{"key":"monthly_fee","desc":"Monthly service fee ZAR"}]', '[{"role":"support","label":"Provider Representative"},{"role":"ipp_developer","label":"Client Representative"}]', 'ZA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_epc_contract_v1', 'epc.contract.standard.v1', 'EPC Contract (FIDIC Silver Book)', 'other', 'EPC/Turnkey Contract — Employer: {{employer_name}} | Contractor: {{contractor_name}} | Project: {{project_name}} | Contract Price: ZAR {{contract_price}} | Completion Date: {{completion_date}} | Liquidated Damages: ZAR {{ld_per_day}} per day. FIDIC Silver Book (1999 Edition) with South African amendments.', '[{"key":"employer_name","desc":"Employer legal name"},{"key":"contractor_name","desc":"EPC contractor"},{"key":"project_name","desc":"Project name"},{"key":"contract_price","desc":"Contract price ZAR"},{"key":"completion_date","desc":"Planned completion date"},{"key":"ld_per_day","desc":"LD rate per day ZAR"}]', '[{"role":"ipp_developer","label":"Employer"},{"role":"epc_contractor","label":"Contractor"}]', 'ZA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_gca_nersa_v1', 'gca.nersa.grid_code.v1', 'Grid Connection Agreement (NERSA Grid Code C-1)', 'other', 'Grid Connection Agreement — Network Operator: {{so_name}} | Applicant: {{applicant_name}} | Facility: {{facility_name}} | Connection Voltage: {{connection_kv}} kV | Contracted Capacity: {{capacity_mw}} MW | Metering Point: {{metering_point}} | NERSA Grid Code §C-1 applies.', '[{"key":"so_name","desc":"Network operator name"},{"key":"applicant_name","desc":"Generator applicant"},{"key":"facility_name","desc":"Generator facility name"},{"key":"connection_kv","desc":"Connection voltage kV"},{"key":"capacity_mw","desc":"Contracted capacity MW"},{"key":"metering_point","desc":"Metering point identifier"}]', '[{"role":"grid_operator","label":"Network Operator"},{"role":"ipp_developer","label":"Generator Applicant"}]', 'ZA-NERSA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_om_agreement_v1', 'om.agreement.standard.v1', 'O&M Services Agreement (IEC 62446)', 'other', 'O&M Services Agreement — Owner: {{owner_name}} | O&M Provider: {{provider_name}} | Site: {{site_name}} | Installed Capacity: {{capacity_kwp}} kWp | Availability Guarantee: {{availability_pct}}% | Response Time P1: {{response_p1_hours}} hours | IEC 62446 and SANS 10142 apply.', '[{"key":"owner_name","desc":"Asset owner"},{"key":"provider_name","desc":"O&M provider"},{"key":"site_name","desc":"Site name"},{"key":"capacity_kwp","desc":"Installed capacity kWp"},{"key":"availability_pct","desc":"Guaranteed availability %"},{"key":"response_p1_hours","desc":"P1 response time hours"}]', '[{"role":"ipp_developer","label":"Asset Owner"},{"role":"esco","label":"O&M Provider"}]', 'ZA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_wheeling_v1', 'wheeling.access.agreement.v1', 'Wheeling Access Agreement (ERA §21)', 'other', 'Wheeling Access Agreement — Network Operator: {{so_name}} | Wheeling Party: {{applicant_name}} | Wheeling Capacity: {{wheeling_mw}} MW | Delivery Point: {{delivery_point}} | Wheeling Charge: ZAR {{tariff_zar_per_mwh}} per MWh | NERSA Grid Code §10 and ERA §21 apply.', '[{"key":"so_name","desc":"Network operator"},{"key":"applicant_name","desc":"Wheeling party"},{"key":"wheeling_mw","desc":"Wheeling capacity MW"},{"key":"delivery_point","desc":"Delivery point"},{"key":"tariff_zar_per_mwh","desc":"Wheeling tariff ZAR/MWh"}]', '[{"role":"grid_operator","label":"Network Operator"},{"role":"offtaker","label":"Wheeling Party"}]', 'ZA-NERSA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_loan_agreement_v1', 'project.finance.loan.v1', 'Project Finance Loan Agreement (LMA)', 'other', 'Project Finance Facility Agreement — Borrower: {{borrower_name}} | Lender: {{lender_name}} | Facility Amount: ZAR {{facility_zar}} | Tenor: {{tenor_years}} years | Interest: {{base_rate}} + {{margin_bps}}bps | DSCR Covenant: {{dscr_floor}}x | SARB Directive 7/2018 applies.', '[{"key":"borrower_name","desc":"Borrower entity"},{"key":"lender_name","desc":"Lender entity"},{"key":"facility_zar","desc":"Facility amount ZAR"},{"key":"tenor_years","desc":"Tenor years"},{"key":"base_rate","desc":"Base rate (JIBAR/PRIME)"},{"key":"margin_bps","desc":"Margin basis points"},{"key":"dscr_floor","desc":"DSCR covenant floor"}]', '[{"role":"ipp_developer","label":"Borrower"},{"role":"lender","label":"Lender"}]', 'ZA-LMA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_carbon_erpa_v1', 'carbon.erpa.forward.v1', 'Carbon ERPA Forward Delivery Agreement', 'other', 'Emission Reduction Purchase Agreement — Seller: {{seller_name}} | Buyer: {{buyer_name}} | Quantity: {{quantity_tco2e}} tCO2e | Vintage: {{vintage_year}} | Price: USD {{price_usd}} per tCO2e | Delivery Date: {{delivery_date}} | Registry: {{registry}} | Corresponding Adjustment: {{ca_required}}. Verra VCS and UNFCCC Article 6 apply.', '[{"key":"seller_name","desc":"Carbon seller"},{"key":"buyer_name","desc":"Carbon buyer"},{"key":"quantity_tco2e","desc":"Quantity tCO2e"},{"key":"vintage_year","desc":"Vintage year"},{"key":"price_usd","desc":"Price USD per tCO2e"},{"key":"delivery_date","desc":"ITMO delivery date"},{"key":"registry","desc":"Registry name"},{"key":"ca_required","desc":"Corresponding adjustment required (yes/no)"}]', '[{"role":"carbon_fund","label":"Seller"},{"role":"offtaker","label":"Buyer"}]', 'ZA-UNFCCC', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_ancillary_service_v1', 'ancillary.service.contract.v1', 'Ancillary Services Contract (Grid Code §G.2)', 'other', 'Ancillary Services Contract — SO: {{so_name}} | Provider: {{provider_name}} | Service Type: {{service_type}} | Capacity: {{capacity_mw}} MW | Availability Payment: ZAR {{availability_zar_per_mw_h}} per MW/h | Utilisation: ZAR {{utilisation_zar_per_mwh}} per MWh | NERSA Grid Code §G.2 applies.', '[{"key":"so_name","desc":"System operator"},{"key":"provider_name","desc":"Provider name"},{"key":"service_type","desc":"Service type (FCR/FRR/RR)"},{"key":"capacity_mw","desc":"Capacity MW"},{"key":"availability_zar_per_mw_h","desc":"Availability payment ZAR/MW/h"},{"key":"utilisation_zar_per_mwh","desc":"Utilisation payment ZAR/MWh"}]', '[{"role":"grid_operator","label":"System Operator"},{"role":"ipp_developer","label":"Provider"}]', 'ZA-NERSA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_insurance_v1', 'project.insurance.master.v1', 'Project Insurance Schedule (FSCA §38)', 'other', 'Insurance Schedule — Insured: {{insured_name}} | Insurer: {{insurer_name}} | Policy No: {{policy_ref}} | Coverage: {{coverage_type}} | Sum Insured: ZAR {{sum_insured}} | Premium: ZAR {{premium_annual}} pa | Expiry: {{expiry_date}} | FSCA Section 38 applies.', '[{"key":"insured_name","desc":"Insured party"},{"key":"insurer_name","desc":"Insurer"},{"key":"policy_ref","desc":"Policy reference"},{"key":"coverage_type","desc":"Coverage type"},{"key":"sum_insured","desc":"Sum insured ZAR"},{"key":"premium_annual","desc":"Annual premium ZAR"},{"key":"expiry_date","desc":"Expiry date"}]', '[{"role":"ipp_developer","label":"Insured"},{"role":"admin","label":"Broker/Underwriter"}]', 'ZA-FSCA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_carbon_ppa_v1', 'ppa.carbon.bundled.v1', 'Carbon-Bundled PPA (Scope 2 + I-REC)', 'other', 'Carbon-Bundled Power Purchase Agreement — Seller: {{seller_name}} | Buyer: {{buyer_name}} | Capacity: {{capacity_mw}} MW | Energy Price: ZAR {{tariff_zar_per_mwh}} per MWh | REC Bundle: {{rec_standard}} | Scope 2 Claim: Market-based per GHG Protocol | NERSA Section 34 and I-REC Standard apply.', '[{"key":"seller_name","desc":"Generator seller"},{"key":"buyer_name","desc":"Offtaker buyer"},{"key":"capacity_mw","desc":"Capacity MW"},{"key":"tariff_zar_per_mwh","desc":"Energy tariff ZAR/MWh"},{"key":"rec_standard","desc":"REC standard (I-REC/SAREC)"}]', '[{"role":"ipp_developer","label":"Generator"},{"role":"offtaker","label":"Offtaker"}]', 'ZA', 1, 'published', 'demo_admin_001');

INSERT OR IGNORE INTO oe_document_templates (id, template_key, display_name, category, body_md, variables_json, required_signatories_json, jurisdiction, version, status, created_by) VALUES ('tpl_ppa_standard_v2', 'ppa.nersa_s34.v2', 'PPA — NERSA Section 34 (Standard Form)', 'ppa', 'Power Purchase Agreement — Generator: {{generator_name}} | Offtaker: {{offtaker_name}} | Facility: {{facility_name}} | Capacity: {{capacity_mw}} MW | Tariff: ZAR {{tariff_zar}} per MWh | Escalation: CPI+{{escalation_pct}}% | Term: {{term_years}} years | COD: {{cod_date}} | NERSA Section 34 applies.', '[{"key":"generator_name","desc":"Generator legal name"},{"key":"offtaker_name","desc":"Offtaker legal name"},{"key":"facility_name","desc":"Facility name"},{"key":"capacity_mw","desc":"Contracted capacity MW"},{"key":"tariff_zar","desc":"Initial tariff ZAR/MWh"},{"key":"escalation_pct","desc":"CPI escalation add-on %"},{"key":"term_years","desc":"PPA term years"},{"key":"cod_date","desc":"Commercial operation date"}]', '[{"role":"ipp_developer","label":"Generator"},{"role":"offtaker","label":"Offtaker"}]', 'ZA-NERSA', 2, 'published', 'demo_admin_001');

